import React, { useEffect, useMemo, useRef, useState, forwardRef, useImperativeHandle } from 'react';
import { Editor, EditorState, ContentState, CompositeDecorator, Modifier, SelectionState } from 'draft-js';
import { Box, Chip, Popper, Paper, List, ListItem, ListItemButton, Typography, useTheme, alpha } from '@mui/material';
import { Tag as TagIcon, Notes as NotesIcon } from '@mui/icons-material';
import { getTagChipStyles, formatTagForDisplay, isGroupedTag, getTagGroup } from '../../utils/tagColors';
import { scrollbarStyles } from '../../styles/scrollbarStyles';
import { Z_INDEX } from '../../styles/zIndex';

export interface AIChatMentionInputProps {
  value: string;
  onChange: (value: string) => void;
  onKeyDown?: (e: React.KeyboardEvent) => void;
  placeholder?: string;
  disabled?: boolean;
  allTags: string[];
  allNotes: { id: string; title: string }[];
  maxRows?: number;
  sx?: any;
}

const createTagMentionComponent = () => {
  const TagMentionEntity = ({ contentState, entityKey }: any) => {
    const theme = useTheme();
    const { tag } = contentState.getEntity(entityKey).getData() as { tag: string };

    // Simple: render a Chip instead of the underlying text. We intentionally
    // do NOT render children here so the raw text is not shown.
    return (
      <Chip
        size="small"
        label={formatTagForDisplay(tag, true)}
        contentEditable={false}
        onMouseDown={(e) => e.preventDefault()}
        sx={{
          ...getTagChipStyles(tag, theme),
          height: 22,
          fontSize: '0.75rem',
          userSelect: 'none',
          verticalAlign: 'middle',
          display: 'inline-flex'
        }}
      />
    );
  };
  (TagMentionEntity as any).displayName = 'TagMentionEntity';
  return TagMentionEntity;
};

const createNoteMentionComponent = () => {
  const NoteMentionEntity = ({ contentState, entityKey }: any) => {
    const theme = useTheme();
    const { noteTitle } = contentState.getEntity(entityKey).getData() as { noteTitle: string };

    return (
      <Chip
        size="small"
        label={noteTitle}
        contentEditable={false}
        onMouseDown={(e) => e.preventDefault()}
        sx={{
          height: 22,
          fontSize: '0.75rem',
          userSelect: 'none',
          verticalAlign: 'middle',
          display: 'inline-flex',
          backgroundColor: alpha(theme.palette.info.main, 0.1),
          color: theme.palette.info.main,
          border: `1px solid ${alpha(theme.palette.info.main, 0.3)}`,
          '&:hover': {
            backgroundColor: alpha(theme.palette.info.main, 0.2)
          }
        }}
      />
    );
  };
  (NoteMentionEntity as any).displayName = 'NoteMentionEntity';
  return NoteMentionEntity;
};

const createMentionDecorator = () =>
  new CompositeDecorator([
    {
      // Render tag mentions as chips
      strategy: (block, callback, contentState) => {
        block.findEntityRanges(
          ch => {
            const k = ch.getEntity();
            return !!k && contentState.getEntity(k).getType() === 'TAG_MENTION';
          },
          (start, end) => callback(start, end)
        );
      },
      component: createTagMentionComponent()
    },
    {
      // Render note mentions as chips
      strategy: (block, callback, contentState) => {
        block.findEntityRanges(
          ch => {
            const k = ch.getEntity();
            return !!k && contentState.getEntity(k).getType() === 'NOTE_MENTION';
          },
          (start, end) => callback(start, end)
        );
      },
      component: createNoteMentionComponent()
    }
  ]);

type MentionItem = { type: 'note'; id: string; title: string } | { type: 'tag'; tag: string };

const AIChatMentionInput = forwardRef<any, AIChatMentionInputProps>(({
  value, onChange, onKeyDown, placeholder, disabled, allTags, allNotes, maxRows = 4, sx
}, ref) => {
  const theme = useTheme();
  const editorRef = useRef<Editor>(null as any);
  const [editorState, setEditorState] = useState(() => EditorState.createWithContent(ContentState.createFromText(value || ''), createMentionDecorator()));
  const editorStateRef = useRef(editorState);
  const [editorKey, setEditorKey] = useState(0);
  const [mention, setMention] = useState<{ open: boolean; term: string; start: number; blockKey: string } | null>(null);
  const [anchorEl, setAnchorEl] = useState<HTMLElement | null>(null);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const moveCursorToEndOnNextUpdate = useRef(false);

  useImperativeHandle(ref, () => ({
    focus: () => editorRef.current && (editorRef.current as any).focus?.(),
    moveCursorToEnd: () => {
      // Set flag to move cursor to end on next value update
      moveCursorToEndOnNextUpdate.current = true;

      // Also try to move it immediately if possible
      const currentContent = editorStateRef.current.getCurrentContent();
      const lastBlock = currentContent.getLastBlock();
      const lastBlockKey = lastBlock.getKey();
      const length = lastBlock.getLength();

      const selection = SelectionState.createEmpty(lastBlockKey).merge({
        anchorOffset: length,
        focusOffset: length
      }) as SelectionState;

      const newState = EditorState.forceSelection(editorStateRef.current, selection);
      setEditorState(newState);

      // Focus after setting selection
      setTimeout(() => {
        (editorRef.current as any)?.focus?.();
      }, 0);
    },
  }));

  useEffect(() => {
    // keep external value in sync if it changes from outside
    const currentText = editorState.getCurrentContent().getPlainText();
    if (value !== currentText) {
      const newContent = ContentState.createFromText(value || '');
      let newState = EditorState.createWithContent(newContent, createMentionDecorator());

      // If we should move cursor to end, do it now
      if (moveCursorToEndOnNextUpdate.current) {
        const lastBlock = newContent.getLastBlock();
        const lastBlockKey = lastBlock.getKey();
        const length = lastBlock.getLength();

        const selection = SelectionState.createEmpty(lastBlockKey).merge({
          anchorOffset: length,
          focusOffset: length
        }) as SelectionState;

        newState = EditorState.forceSelection(newState, selection);
        moveCursorToEndOnNextUpdate.current = false;

        // Focus the editor
        setTimeout(() => {
          (editorRef.current as any)?.focus?.();
        }, 0);
      }

      setEditorState(newState);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [value]);

  useEffect(() => {
    editorStateRef.current = editorState;
  }, [editorState]);

  useEffect(() => {
    if (editorKey > 0) {
      const raf = requestAnimationFrame(() => {
        try { (editorRef.current as any)?.focus?.(); } catch (_) {}
      });
      return () => cancelAnimationFrame(raf);
    }
  }, [editorKey]);

  const tags = useMemo(() => allTags.sort(), [allTags]);

  const filteredNotes = useMemo(() => {
    const term = mention?.term?.toLowerCase() ?? '';
    return (term
      ? allNotes.filter(n => (n.title || '').toLowerCase().includes(term))
      : allNotes
    ).slice(0, 20);
  }, [allNotes, mention?.term]);

  const filteredTags = useMemo(() => {
    const term = mention?.term?.toLowerCase() ?? '';
    return (term ? tags.filter(t => t.toLowerCase().includes(term)) : tags).slice(0, 30);
  }, [tags, mention?.term]);

  const flatItems = useMemo<MentionItem[]>(() => [
    ...filteredNotes.map(n => ({ type: 'note' as const, id: n.id, title: n.title })),
    ...filteredTags.map(t => ({ type: 'tag' as const, tag: t }))
  ], [filteredNotes, filteredTags]);

  function updateMentionState(state: EditorState) {
    const sel = state.getSelection();
    if (!sel.isCollapsed()) return setMention(null);
    const content = state.getCurrentContent();
    const blockKey = sel.getStartKey();
    const block = content.getBlockForKey(blockKey);
    const offset = sel.getStartOffset();
    const text = block.getText().slice(0, offset);
    const at = text.lastIndexOf('/');
    if (at === -1) return setMention(null);
    if (at > 0 && /[^\s]/.test(text[at - 1])) return setMention(null);
    const term = text.slice(at + 1);
    if (/[^A-Za-z0-9:_.-]/.test(term)) return setMention(null);
    setMention({ open: true, term, start: at, blockKey });
    setAnchorEl(containerRef.current);
    setSelectedIndex(0);
  }

  function handleChange(state: EditorState) {
    setEditorState(state);
    onChange(state.getCurrentContent().getPlainText());
    updateMentionState(state);
  }

  function handleKeyDownLocal(e: React.KeyboardEvent) {
    if (mention?.open) {
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex((i) => Math.min(i + 1, flatItems.length - 1)); return; }
      if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex((i) => Math.max(i - 1, 0)); return; }
      if (e.key === 'Enter') {
        e.preventDefault();
        const item = flatItems[selectedIndex];
        if (item) {
          if (item.type === 'tag') insertTag(item.tag);
          else insertNoteFromMention(item);
        }
        return;
      }
      if (e.key === 'Escape') { e.preventDefault(); setMention(null); return; }
    }

    // Prevent @ from being inserted - we'll handle it in handleChange via updateMentionState
    if (e.key === '@' && !e.ctrlKey && !e.metaKey && !e.altKey) {
      // Don't prevent default - let Draft.js insert the @ so updateMentionState can detect it
      // The @ will be replaced when a tag is selected
    }

    const sel = editorState.getSelection();
    if (sel.isCollapsed()) {
      const content = editorState.getCurrentContent();
      const block = content.getBlockForKey(sel.getStartKey());
      const offset = sel.getStartOffset();
      if (e.key === 'Backspace' && offset > 0) {
        const text = block.getText();
        if (text[offset - 1] === ' ' && offset > 1) {
          const ekBeforeSpace = block.getEntityAt(offset - 2);
          if (ekBeforeSpace) {
            const entityType = content.getEntity(ekBeforeSpace).getType();
            if (entityType === 'TAG_MENTION' || entityType === 'NOTE_MENTION') {
              e.preventDefault();
              handleRemoveEntity(ekBeforeSpace, true);
              return;
            }
          }
        }

        const ek = block.getEntityAt(offset - 1);
        if (ek) {
          const entityType = content.getEntity(ek).getType();
          if (entityType === 'TAG_MENTION' || entityType === 'NOTE_MENTION') {
            e.preventDefault();
            handleRemoveEntity(ek);
            return;
          }
        }
      }
    }
    onKeyDown?.(e);
  }

  function insertNoteFromMention(note: { id: string; title: string }) {
    const state = editorStateRef.current || editorState;
    const selection = state.getSelection();
    if (!selection.isCollapsed()) { setMention(null); return; }

    const content = state.getCurrentContent();
    const blockKey = selection.getStartKey();
    const block = content.getBlockForKey(blockKey);
    const text = block.getText();
    const offset = selection.getStartOffset();

    // Find the '/' by scanning backward (same logic as insertTag)
    let atIndex = -1;
    for (let i = offset - 1; i >= 0; i -= 1) {
      const ch = text[i];
      if (ch === '/') {
        if (i === 0 || /\s/.test(text[i - 1])) { atIndex = i; }
        break;
      }
      if (/\s/.test(ch)) break;
    }
    if (atIndex === -1) { setMention(null); return; }

    const noteTitle = note.title || 'Untitled';

    // Replace @term with the note title
    const replaceSel = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: offset
    }) as SelectionState;
    let newContent = Modifier.replaceText(content, replaceSel, noteTitle);

    // Create NOTE_MENTION entity and apply it
    newContent = newContent.createEntity('NOTE_MENTION', 'IMMUTABLE', { noteTitle, noteId: note.id });
    const entityKey = newContent.getLastCreatedEntityKey();
    const entityRange = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: atIndex + noteTitle.length
    }) as SelectionState;
    newContent = Modifier.applyEntity(newContent, entityRange, entityKey);

    // Insert trailing space
    const afterMention = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + noteTitle.length,
      focusOffset: atIndex + noteTitle.length
    }) as SelectionState;
    newContent = Modifier.insertText(newContent, afterMention, ' ');

    // Create new state with forceSelection — use createWithContent to force full re-render
    // (EditorState.push can leave stale DOM when IMMUTABLE entities are adjacent)
    const cursorPosition = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + noteTitle.length + 1,
      focusOffset: atIndex + noteTitle.length + 1
    }) as SelectionState;
    let newState = EditorState.createWithContent(newContent, createMentionDecorator());
    newState = EditorState.forceSelection(newState, cursorPosition);

    setEditorKey(k => k + 1);
    setMention(null);
    handleChange(newState);
  }

  function insertTag(tag: string) {
    // Always operate on the latest editor state
    const state = editorStateRef.current || editorState;
    const selection = state.getSelection();

    // We only handle collapsed selection (caret position)
    if (!selection.isCollapsed()) {
      setMention(null);
      return;
    }

    const content = state.getCurrentContent();
    const blockKey = selection.getStartKey();
    const block = content.getBlockForKey(blockKey);
    const text = block.getText();
    const offset = selection.getStartOffset();

    // Find the '/' that starts this mention by scanning backwards from the cursor
    let atIndex = -1;
    for (let i = offset - 1; i >= 0; i -= 1) {
      const ch = text[i];
      if (ch === '/') {
        // Require start-of-line or whitespace before '/' so we don't match paths, etc.
        if (i === 0 || /\s/.test(text[i - 1])) {
          atIndex = i;
        }
        break;
      }
      if (/\s/.test(ch)) {
        // Hit whitespace before finding a '/' – no valid mention here
        break;
      }
    }

    if (atIndex === -1) {
      setMention(null);
      return;
    }

    const mentionText = tag; // raw tag, without '@'

    // Selection from '@' up to current caret position
    const replaceSel = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: offset
    }) as SelectionState;

    // Step 1: replace the @mention text with the tag text
    let newContent = Modifier.replaceText(content, replaceSel, mentionText);

    // Step 2: create an entity for this tag and apply it over the inserted text
    newContent = newContent.createEntity('TAG_MENTION', 'IMMUTABLE', { tag });
    const entityKey = newContent.getLastCreatedEntityKey();

    const entityRange = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex,
      focusOffset: atIndex + mentionText.length
    }) as SelectionState;
    newContent = Modifier.applyEntity(newContent, entityRange, entityKey);

    // Step 3: insert a trailing space after the chip
    const afterMention = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + mentionText.length,
      focusOffset: atIndex + mentionText.length
    }) as SelectionState;
    newContent = Modifier.insertText(newContent, afterMention, ' ');

    // Use createWithContent to force full re-render (EditorState.push leaves stale DOM
    // when IMMUTABLE entities are adjacent to the inserted text)
    const cursorPosition = SelectionState.createEmpty(blockKey).merge({
      anchorOffset: atIndex + mentionText.length + 1,
      focusOffset: atIndex + mentionText.length + 1
    }) as SelectionState;
    let newState = EditorState.createWithContent(newContent, createMentionDecorator());
    newState = EditorState.forceSelection(newState, cursorPosition);

    setEditorKey(k => k + 1);
    setMention(null);
    handleChange(newState);
  }

  function handleRemoveEntity(entityKey: string, includeFollowingSpace = false) {
    const state = editorStateRef.current || editorState;
    const content = state.getCurrentContent();
    const blocks = content.getBlocksAsArray();
    for (const b of blocks) {
      let s = -1, e = -1;
      b.findEntityRanges(ch => ch.getEntity() === entityKey, (start, end) => { s = start; e = end; });
      if (s >= 0) {
        let focusOffset = e;
        if (includeFollowingSpace) {
          const txt = b.getText();
          if (txt[e] === ' ') focusOffset = e + 1;
        }
        const sel = SelectionState.createEmpty(b.getKey()).merge({ anchorOffset: s, focusOffset }) as SelectionState;
        const c2 = Modifier.removeRange(content, sel, 'backward');
        const st = EditorState.push(state, c2, 'remove-range');
        setEditorKey(k => k + 1);
        handleChange(st);
        return;
      }
    }
  }

  return (
    <Box ref={containerRef} sx={{ position: 'relative', width: '100%' }}>
      <Box
        onClick={() => editorRef.current && (editorRef.current as any).focus?.()}
        onKeyDown={handleKeyDownLocal}
        sx={{
          display: 'flex', flexWrap: 'wrap', alignItems: 'center', gap: 0.5,
          px: 1, py: 0.5, border: 'none', backgroundColor: 'transparent', cursor: 'text',
          width: '100%', maxWidth: '100%', minWidth: 0,
          '& .DraftEditor-root': { width: '100%' },
          '& .public-DraftEditor-content': {
            whiteSpace: 'pre-wrap',
            wordBreak: 'break-word',
            overflowWrap: 'anywhere',
            maxHeight: `${maxRows * 1.6}em`,
            overflowY: 'auto',
            ...scrollbarStyles(theme)
          },
          '& .public-DraftEditorPlaceholder-root': { whiteSpace: 'pre-wrap' },
          ...sx
        }}
      >
        <Editor
          key={editorKey}
          ref={editorRef as any}
          editorState={editorState}
          onChange={handleChange}
          readOnly={!!disabled}
          placeholder={placeholder}
          handleReturn={() => mention?.open ? 'handled' : 'not-handled'}
        />
      </Box>

      <Popper
        open={!!mention?.open}
        anchorEl={anchorEl}
        placement="top-start"
        sx={{ zIndex: Z_INDEX.RICH_TEXT_MENU }}
      >
        <Paper
          elevation={8}
          sx={{
            maxHeight: 260,
            minWidth: 260,
            maxWidth: 420,
            overflow: 'hidden',
            border: '1px solid',
            borderColor: 'divider'
          }}
        >
          <Box
            sx={{
              p: 1.5,
              borderBottom: '1px solid',
              borderColor: 'divider',
              backgroundColor: alpha(theme.palette.primary.main, 0.04)
            }}
          >
            <Typography
              variant="caption"
              color="text.secondary"
              sx={{ display: 'flex', alignItems: 'center', gap: 0.5, fontWeight: 500 }}
            >
              <TagIcon sx={{ fontSize: 14 }} /> Select a tag or note ({flatItems.length} available)
            </Typography>
          </Box>
          <List sx={{ maxHeight: 200, overflow: 'auto', p: 0, ...scrollbarStyles(theme) }}>
            {flatItems.length === 0 ? (
              <ListItem>
                <Box sx={{ p: 2, textAlign: 'center', width: '100%' }}>
                  <Typography variant="body2" color="text.secondary">
                    {allTags.length === 0 && allNotes.length === 0
                      ? 'No tags or notes available.'
                      : `No matches for "${mention?.term || ''}"`}
                  </Typography>
                </Box>
              </ListItem>
            ) : (
              <>
                {filteredNotes.length > 0 && (
                  <>
                    <ListItem
                      sx={{
                        py: 0.5,
                        px: 2,
                        backgroundColor: alpha(theme.palette.info.main, 0.04),
                        borderBottom: '1px solid',
                        borderColor: 'divider'
                      }}
                    >
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{ display: 'flex', alignItems: 'center', gap: 0.5, fontWeight: 600 }}
                      >
                        <NotesIcon sx={{ fontSize: 12 }} /> Notes
                      </Typography>
                    </ListItem>
                    {filteredNotes.map((note, idx) => (
                      <ListItem key={note.id} disablePadding>
                        <ListItemButton
                          selected={idx === selectedIndex}
                          onMouseDown={(e) => { e.preventDefault(); insertNoteFromMention(note); }}
                          onClick={(e) => { e.preventDefault(); insertNoteFromMention(note); }}
                          sx={{ py: 1, px: 2 }}
                        >
                          <Typography variant="body2" noWrap>
                            {note.title || 'Untitled'}
                          </Typography>
                        </ListItemButton>
                      </ListItem>
                    ))}
                  </>
                )}
                {filteredTags.length > 0 && (
                  <>
                    <ListItem
                      sx={{
                        py: 0.5,
                        px: 2,
                        backgroundColor: alpha(theme.palette.primary.main, 0.04),
                        borderBottom: '1px solid',
                        borderColor: 'divider'
                      }}
                    >
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{ display: 'flex', alignItems: 'center', gap: 0.5, fontWeight: 600 }}
                      >
                        <TagIcon sx={{ fontSize: 12 }} /> Tags
                      </Typography>
                    </ListItem>
                    {filteredTags.map((tag, idx) => {
                      const flatIdx = filteredNotes.length + idx;
                      return (
                        <ListItem key={tag} disablePadding>
                          <ListItemButton
                            selected={flatIdx === selectedIndex}
                            onMouseDown={(e) => { e.preventDefault(); insertTag(tag); }}
                            onClick={(e) => { e.preventDefault(); insertTag(tag); }}
                            sx={{ py: 1, px: 2 }}
                          >
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, width: '100%' }}>
                              <Chip
                                label={formatTagForDisplay(tag, true)}
                                size="small"
                                sx={{ ...getTagChipStyles(tag, theme), height: 20, fontSize: '0.7rem' }}
                              />
                              {isGroupedTag(tag) && (
                                <Typography variant="caption" color="text.secondary">
                                  {getTagGroup(tag)}
                                </Typography>
                              )}
                            </Box>
                          </ListItemButton>
                        </ListItem>
                      );
                    })}
                  </>
                )}
              </>
            )}
          </List>
        </Paper>
      </Popper>
    </Box>
  );
});

AIChatMentionInput.displayName = 'AIChatMentionInput';
export default AIChatMentionInput;

